 1→/**
 2→ * Common utility functions for Maimai Assistant web UI.
 3→ */
 4→
 5→function escapeHtml(str) {
 6→    if (!str) return '';
 7→    const div = document.createElement('div');
 8→    div.textContent = str;
 9→    return div.innerHTML;
10→}
11→
12→/**
13→ * Fetch wrapper with automatic res.ok check.
14→ * Extracts FastAPI error detail when available.
15→ */
16→async function safeFetch(url, options) {
17→    const res = await fetch(url, options);
18→    if (!res.ok) {
19→        let detail = res.statusText;
20→        try {
21→            const err = await res.json();
22→            detail = err.detail || err.error || detail;
23→        } catch { /* response wasn't JSON */ }
24→        throw new Error(`HTTP ${res.status}: ${detail}`);
25→    }
26→    return res;
27→}
28→
29→/**
30→ * Poll a task until it completes (fallback when WebSocket is not available).
31→ */
32→async function pollTask(taskId, onUpdate, intervalMs = 2000, maxAttempts = 300) {
33→    for (let i = 0; i < maxAttempts; i++) {
34→        try {
35→            const res = await safeFetch(`/api/task/${taskId}`);
36→            const data = await res.json();
37→            if (onUpdate) onUpdate(data);
38→
39→            if (data.status === 'completed' || data.status === 'failed' || data.status === 'cancelled') {
40→                return data;
41→            }
42→        } catch (e) {
43→            console.error('Poll error:', e);
44→        }
45→        await new Promise(r => setTimeout(r, intervalMs));
46→    }
47→    return null;
48→}

  1→/**
  2→ * Pipeline page interaction logic.
  3→ * Supports dual mode: search-only (no template) and pipeline (with template).
  4→ */
  5→
  6→let pipelineTaskId = null;
  7→let pipelineWS = null;
  8→let pipelineCandidates = [];
  9→
 10→// --- Log helper ---
 11→
 12→function clearLog() {
 13→    const log = document.getElementById('pipeline-log');
 14→    if (log) log.innerHTML = '';
 15→}
 16→
 17→function appendLog(text, level = 'info') {
 18→    const log = document.getElementById('pipeline-log');
 19→    if (!log) return;
 20→    const time = new Date().toLocaleTimeString();
 21→    const line = document.createElement('div');
 22→    line.className = 'log-line';
 23→    line.innerHTML = `<span class="log-time">${time}</span><span class="log-${level}">${escapeHtml(text)}</span>`;
 24→    log.appendChild(line);
 25→    log.scrollTop = log.scrollHeight;
 26→}
 27→
 28→// --- Form submission ---
 29→
 30→document.getElementById('pipeline-form').addEventListener('submit', async (e) => {
 31→    e.preventDefault();
 32→    const form = e.target;
 33→
 34→    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
 35→    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
 36→    const location = form.location ? form.location.value.trim() || null : null;
 37→    const template = form.template.value;
 38→    const pages = parseInt(form.pages.value) || 1;
 39→
 40→    if (!keywords.length) return alert('Please enter at least one keyword');
 41→
 42→    // Hide all result sections, reset log
 43→    document.getElementById('pipeline-progress').hidden = false;
 44→    document.getElementById('pipeline-confirm').hidden = true;
 45→    document.getElementById('pipeline-results').hidden = true;
 46→    document.getElementById('search-results').hidden = true;
 47→    document.getElementById('pipeline-progress-bar').value = 0;
 48→    form.querySelector('button[type="submit"]').disabled = true;
 49→    clearLog();
 50→
 51→    const isSearchOnly = !template;
 52→
 53→    if (isSearchOnly) {
 54→        // --- Search-only mode ---
 55→        appendLog(`Starting search: ${keywords.join(', ')} | pages=${pages}`);
 56→        try {
 57→            const res = await safeFetch('/api/search', {
 58→                method: 'POST',
 59→                headers: {'Content-Type': 'application/json'},
 60→                body: JSON.stringify({keywords, company, location, pages}),
 61→            });
 62→            const data = await res.json();
 63→            pipelineTaskId = data.task_id;
 64→            document.getElementById('pipeline-task-id').textContent = data.task_id;
 65→            document.getElementById('pipeline-status-text').textContent = 'Searching...';
 66→            appendLog(`Task queued: ${data.task_id}`);
 67→
 68→            connectTaskWS(data.task_id, {
 69→                onEvent(msg) {
 70→                    document.getElementById('pipeline-status-text').textContent =
 71→                        `${msg.event}: ${msg.keyword || ''} ${msg.found ? '(' + msg.found + ' found)' : ''}`;
 72→                    if (msg.event === 'search_keyword_done') {
 73→                        appendLog(`"${msg.keyword}" — found ${msg.found} candidates (total: ${msg.total_so_far})`, 'ok');
 74→                    } else if (msg.keyword) {
 75→                        appendLog(`Searching: ${msg.keyword}`);
 76→                    }
 77→                },
 78→                onComplete(msg) {
 79→                    const candidates = msg.result || [];
 80→                    appendLog(`Search complete — ${candidates.length} candidates found`, 'ok');
 81→                    showSearchResults(candidates);
 82→                    document.getElementById('pipeline-progress').hidden = true;
 83→                    form.querySelector('button[type="submit"]').disabled = false;
 84→                },
 85→                onError(msg) {
 86→                    const err = msg.error || 'Unknown error';
 87→                    appendLog(`Search failed: ${err}`, 'err');
 88→                    document.getElementById('pipeline-status-text').textContent = 'Failed';
 89→                    form.querySelector('button[type="submit"]').disabled = false;
 90→                },
 91→            });
 92→        } catch (e) {
 93→            appendLog(`Request failed: ${e.message}`, 'err');
 94→            document.getElementById('pipeline-progress').hidden = true;
 95→            form.querySelector('button[type="submit"]').disabled = false;
 96→        }
 97→    } else {
 98→        // --- Pipeline mode ---
 99→        const auto_send = form.auto_send.checked;
100→
101→        // Collect template variables
102→        const variables = {};
103→        form.querySelectorAll('[name^="var_"]').forEach(input => {
104→            const key = input.name.replace('var_', '');
105→            if (input.value.trim()) variables[key] = input.value.trim();
106→        });
107→
108→        appendLog(`Starting pipeline: ${keywords.join(', ')} | template=${template} | auto_send=${auto_send}`);
109→
110→        try {
111→            const res = await safeFetch('/api/pipeline', {
112→                method: 'POST',
113→                headers: {'Content-Type': 'application/json'},
114→                body: JSON.stringify({keywords, company, location, template, pages, variables, auto_send}),
115→            });
116→            const data = await res.json();
117→            pipelineTaskId = data.task_id;
118→            document.getElementById('pipeline-task-id').textContent = data.task_id;
119→            appendLog(`Task queued: ${data.task_id}`);
120→
121→            pipelineWS = connectTaskWS(data.task_id, {
122→                onEvent(msg) {
123→                    handlePipelineEvent(msg);
124→                },
125→                onComplete(msg) {
126→                    appendLog('Pipeline completed', 'ok');
127→                    showPipelineResults(msg.result);
128→                    document.getElementById('pipeline-progress').hidden = true;
129→                    form.querySelector('button[type="submit"]').disabled = false;
130→                },
131→                onError(msg) {
132→                    const err = msg.error || 'Unknown error';
133→                    appendLog(`Pipeline failed: ${err}`, 'err');
134→                    document.getElementById('pipeline-status-text').textContent = 'Failed';
135→                    document.getElementById('pipeline-detail').textContent = err;
136→                    form.querySelector('button[type="submit"]').disabled = false;
137→                },
138→            });
139→
140→            pollTask(data.task_id, (task) => {
141→                if (task.status === 'completed') {
142→                    showPipelineResults(task.result);
143→                    document.getElementById('pipeline-progress').hidden = true;
144→                    form.querySelector('button[type="submit"]').disabled = false;
145→                    if (pipelineWS) pipelineWS.close();
146→                }
147→            }, 3000);
148→
149→        } catch (e) {
150→            appendLog(`Request failed: ${e.message}`, 'err');
151→            form.querySelector('button[type="submit"]').disabled = false;
152→            document.getElementById('pipeline-progress').hidden = true;
153→        }
154→    }
155→});
156→
157→function handlePipelineEvent(msg) {
158→    const statusEl = document.getElementById('pipeline-status-text');
159→    const detailEl = document.getElementById('pipeline-detail');
160→    const progressBar = document.getElementById('pipeline-progress-bar');
161→
162→    switch (msg.event) {
163→        case 'search_progress':
164→            statusEl.textContent = `Searching: ${msg.keyword} (${msg.keyword_index}/${msg.total_keywords})`;
165→            appendLog(`Searching keyword ${msg.keyword_index}/${msg.total_keywords}: "${msg.keyword}"`);
166→            break;
167→
168→        case 'search_keyword_done':
169→            detailEl.textContent = `Found ${msg.found} candidates for "${msg.keyword}" (${msg.total_so_far} total)`;
170→            appendLog(`"${msg.keyword}" — found ${msg.found} (total: ${msg.total_so_far})`, 'ok');
171→            break;
172→
173→        case 'search_complete':
174→            statusEl.textContent = 'Search complete';
175→            detailEl.textContent = `${msg.candidates.length} candidates found`;
176→            appendLog(`Search phase done — ${msg.candidates.length} candidates`, 'ok');
177→            break;
178→
179→        case 'awaiting_confirmation':
180→            statusEl.textContent = 'Awaiting your confirmation';
181→            appendLog(`Waiting for confirmation — ${msg.candidates.length} candidates to review`, 'warn');
182→            document.getElementById('pipeline-progress').hidden = true;
183→            showConfirmation(msg.candidates);
184→            break;
185→
186→        case 'sending_started':
187→            statusEl.textContent = 'Sending messages...';
188→            progressBar.max = msg.total;
189→            progressBar.value = 0;
190→            document.getElementById('pipeline-progress').hidden = false;
191→            document.getElementById('pipeline-confirm').hidden = true;
192→            appendLog(`Sending messages to ${msg.total} candidates...`);
193→            break;
194→
195→        case 'send_progress':
196→            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
197→            progressBar.value = msg.sent + msg.failed;
198→            progressBar.max = msg.total;
199→            detailEl.textContent = `Sent: ${msg.sent}, Failed: ${msg.failed}`;
200→            if (msg.status === 'sent') {
201→                appendLog(`Sent to ${msg.current}`, 'ok');
202→            } else if (msg.status === 'failed') {
203→                appendLog(`Failed: ${msg.current} — ${msg.error || 'unknown'}`, 'err');
204→            } else if (msg.status === 'skipped') {
205→                appendLog(`Skipped: ${msg.current}`, 'warn');
206→            } else {
207→                appendLog(`${msg.current} (${msg.sent}/${msg.total})`);
208→            }
209→            break;
210→
211→        case 'completed':
212→            appendLog('Pipeline completed', 'ok');
213→            showPipelineResults(msg.result);
214→            break;
215→
216→        default:
217→            appendLog(`${msg.event}: ${JSON.stringify(msg)}`);
218→    }
219→}
220→
221→function showConfirmation(candidates) {
222→    pipelineCandidates = candidates;
223→    document.getElementById('pipeline-confirm').hidden = false;
224→    document.getElementById('confirm-count').textContent = candidates.length;
225→
226→    const list = document.getElementById('candidate-list');
227→    list.innerHTML = candidates.map(c => `
228→        <label>
229→            <input type="checkbox" value="${escapeHtml(c.maimai_id)}" checked>
230→            <span class="candidate-info">
231→                <span class="candidate-name">${escapeHtml(c.name)}</span>
232→                <span class="candidate-title">${escapeHtml(c.title)}</span>
233→                <span class="candidate-company">${escapeHtml(c.company)}</span>
234→            </span>
235→        </label>
236→    `).join('');
237→}
238→
239→function toggleSelectAll(checked) {
240→    document.querySelectorAll('#candidate-list input[type="checkbox"]').forEach(cb => {
241→        cb.checked = checked;
242→    });
243→}
244→
245→async function confirmCandidates(cancel = false) {
246→    if (!pipelineTaskId) return;
247→
248→    let maimai_ids = [];
249→    if (!cancel) {
250→        document.querySelectorAll('#candidate-list input[type="checkbox"]:checked').forEach(cb => {
251→            maimai_ids.push(cb.value);
252→        });
253→
254→        if (!maimai_ids.length) {
255→            return alert('Please select at least one candidate');
256→        }
257→    }
258→
259→    try {
260→        await safeFetch(`/api/pipeline/${pipelineTaskId}/confirm`, {
261→            method: 'POST',
262→            headers: {'Content-Type': 'application/json'},
263→            body: JSON.stringify({maimai_ids}),
264→        });
265→
266→        document.getElementById('pipeline-confirm').hidden = true;
267→        if (!cancel) {
268→            document.getElementById('pipeline-progress').hidden = false;
269→            document.getElementById('pipeline-status-text').textContent = 'Sending messages...';
270→            appendLog(`Confirmed ${maimai_ids.length} candidates, sending...`);
271→        } else {
272→            appendLog('Cancelled by user', 'warn');
273→        }
274→    } catch (e) {
275→        appendLog(`Confirm failed: ${e.message}`, 'err');
276→        alert('Confirm failed: ' + e.message);
277→    }
278→}
