280→// --- Search-only results ---
281→
282→function showSearchResults(candidates) {
283→    document.getElementById('search-results').hidden = false;
284→    document.getElementById('result-count').textContent = candidates.length;
285→    const tbody = document.getElementById('results-body');
286→    tbody.innerHTML = candidates.map((c, i) => `
287→        <tr>
288→            <td>${i + 1}</td>
289→            <td>${escapeHtml(c.name)}</td>
290→            <td>${escapeHtml(c.title)}</td>
291→            <td>${escapeHtml(c.company)}</td>
292→            <td>${escapeHtml(c.location || '')}</td>
293→        </tr>
294→    `).join('');
295→}
