297→async function exportResults() {
298→    try {
299→        const res = await safeFetch('/api/export', {
300→            method: 'POST',
301→            headers: {'Content-Type': 'application/json'},
302→            body: JSON.stringify({format: 'xlsx'}),
303→        });
304→        const blob = await res.blob();
305→        const url = URL.createObjectURL(blob);
306→        const a = document.createElement('a');
307→        a.href = url;
308→        a.download = 'candidates.xlsx';
309→        a.click();
310→        URL.revokeObjectURL(url);
311→    } catch (e) {
312→        alert('Export failed: ' + e.message);
313→    }
314→}
