316→// --- Pipeline results ---
317→
318→function showPipelineResults(result) {
319→    document.getElementById('pipeline-progress').hidden = true;
320→    document.getElementById('pipeline-confirm').hidden = true;
321→    document.getElementById('pipeline-results').hidden = false;
322→
323→    const summary = document.getElementById('results-summary');
